VALUES
  ('diplomatic-535efab1-moex-00086', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '依司法院大法官解釋意旨，關於性言論，下列敘述何者錯誤？', '["立法機關為維持社會風化，得以法律限制性言論", "具藝術性、醫學性或教育性之性言論，須採取適當安全隔絕措施，方受憲法保障", "含有性暴力、性虐待或人獸性交且不具藝術性、醫學性或教育性價值之言論，不受憲法保障", "性交易言論若非以兒少為對象或促使兒少為性交易，且訊息之接收人僅限成年人，亦屬憲法所保障 之商業性言論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00087', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '有關人民團體法與結社自由，下列敘述何者錯誤？', '["基於結社自由，人民團體得自主選擇其名稱", "對於人民結社所為之各項限制，以設立管制最為嚴重，應受比例原則之嚴格審查", "為確保自由民主憲政秩序，主管機關對主張共產主義或分裂國土之人民團體得直接不予許可設立", "政黨之解散，由主管機關檢同相關事證移送司法院大法官組成憲法法庭審理之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00088', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '依司法院大法官解釋意旨，政府採購得標廠商國內員工逾百人者應進用一定比例原住民，未進用者應 令繳代金之規定，不涉及下列何者？', '["平等原則", "財產權", "營業自由", "生存權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00089', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '刑事案件審判中，原則上應使被告得以適當方式適時獲知其被訴案件之卷宗及證物全部內容。此涉及 何種訴訟原則？', '["公開審理原則", "法定法官原則", "訴訟上武器平等原則", "直接審判原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00090', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '下列何種案件得於總統在位期間，將其列為犯罪嫌疑人，並開啟偵查程序？', '["總統涉嫌傷害", "總統涉嫌貪污", "總統涉嫌毀謗", "總統涉嫌外患"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00091', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '有關憲法訴訟法所定之各聲請主體及要件，下列敘述何者正確？', '["總統得以其行使職權，適用憲法發生疑義為由，聲請憲法法庭判決", "現有總額三分之一以上之立法委員，得以其行使職權，適用憲法發生疑義為由，聲請憲法法庭判決", "地方自治行政機關如認有關非地方自治事項所應適用之法規範違憲，報請上級機關聲請憲法法庭判決", "懲戒法院法官於其審理中之案件，認應適用之命令違憲，得聲請憲法法庭判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00092', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '下列何者不是司法院之職權？', '["民、刑事及行政訴訟之審判", "犯罪偵查", "公務員懲戒", "審理政黨違憲之解散事項"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00093', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '依臺灣地區與大陸地區人民關係條例第 65 條第 1 款規定：「臺灣地區人民收養大陸地區人民為養子 女，……有下列情形之一者，法院亦應不予認可：一、已有子女或養子女者。」依司法院大法官解釋， 此一規定是否合憲？', '["合憲，因為憲法並未保障收養自由，收養對象之規定純屬立法裁量", "違憲，因臺灣地區人民收養其配偶之大陸地區子女，法院亦應不予認可部分，有違憲法第22條保 障收養自由之意旨", "合憲，因本法涉及兩岸關係，為司法不應解釋之政治問題", "違憲，因臺灣地區人民收養其他國家、地區人民為養子女，並無此等限制，系爭規定違反憲法第7 條平等權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00094', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '下列何者屬於程序基本權？', '["複決權", "創制權", "服公職權", "訴訟權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL),
  ('diplomatic-535efab1-moex-00095', 'diplomatic-535efab1', 'diplomatic-535efab1-moex-114-c655adf3', 'sub-diplomatic-535efab1-05', NULL, 'single_choice', '依立法院的組織與運作之規定，下列敘述何者錯誤？', '["立法院設院長、副院長各一人，由立法委員互選產生", "立法院院長、副院長不得擔任政黨職務，應本公平中立原則行使職權，維持立法院秩序，處理議事", "立法院會議，應公開舉行，不得開秘密會議", "立法院臨時會，以決議召集臨時會之特定事項為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:33+00:00", "source_pdf_sha1": "74e57a3571a6", "answer_pdf_sha1": "b3f1a7073313", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-英文組"}'::jsonb, NULL)
